package types

import (
	"fmt"
	"time"
)

// SandboxEntryPoint represents a single entry point for a sandbox
type SandboxEntryPoint struct {
	// Path is the URL path prefix
	Path string `json:"path"`
	// Protocol is the protocol (HTTP or HTTPS)
	Protocol string `json:"protocol"`
	// Endpoint is the host:port endpoint
	Endpoint string `json:"endpoint"`
}

// SandboxInfo represents sandbox metadata stored in the session store
type SandboxInfo struct {
	// Kind is the resource kind (AgentRuntime or CodeInterpreter)
	Kind string `json:"kind"`
	// SandboxID is the unique sandbox identifier
	SandboxID string `json:"sandboxId"`
	// SandboxNamespace is the Kubernetes namespace
	SandboxNamespace string `json:"sandboxNamespace"`
	// Name is the sandbox name
	Name string `json:"name"`
	// EntryPoints are the available entry points
	EntryPoints []SandboxEntryPoint `json:"entryPoints"`
	// SessionID is the unique session identifier
	SessionID string `json:"sessionId"`
	// CreatedAt is the creation timestamp
	CreatedAt time.Time `json:"createdAt"`
	// ExpiresAt is the expiry timestamp
	ExpiresAt time.Time `json:"expiresAt"`
	// Status is the sandbox status
	Status string `json:"status"`
}

// Constants for sandbox kinds
const (
	AgentRuntimeKind    = "AgentRuntime"
	CodeInterpreterKind = "CodeInterpreter"
	SandboxKind         = "Sandbox"
	SandboxClaimsKind   = "SandboxClaim"
)

// Constants for sandbox status
const (
	SandboxStatusPending    = "pending"
	SandboxStatusRunning    = "running"
	SandboxStatusFailed     = "failed"
	SandboxStatusTerminated = "terminated"
)

// Constants for timeouts
const (
	DefaultSandboxIdleTimeout    = 15 * time.Minute
	DefaultMaxSessionDuration    = 8 * time.Hour
	DefaultSessionTimeout        = 15 * time.Minute
	SandboxCreationTimeout       = 2 * time.Minute
	SandboxDeletionTimeout       = 30 * time.Second
	GCTickInterval               = 15 * time.Second
	GCContextTimeout             = 2 * time.Minute
	DefaultMaxConcurrentRequests = 1000
)

// CreateSandboxRequest represents a request to create a sandbox
type CreateSandboxRequest struct {
	Kind      string `json:"kind"`
	Name      string `json:"name"`
	Namespace string `json:"namespace"`
}

// Validate validates the CreateSandboxRequest
func (car *CreateSandboxRequest) Validate() error {
	if car.Namespace == "" {
		return fmt.Errorf("namespace is required")
	}
	if car.Name == "" {
		return fmt.Errorf("name is required")
	}
	if car.Kind != AgentRuntimeKind && car.Kind != CodeInterpreterKind {
		return fmt.Errorf("invalid kind: %s", car.Kind)
	}
	return nil
}

// CreateSandboxResponse represents a response from creating a sandbox
type CreateSandboxResponse struct {
	SessionID   string              `json:"sessionId"`
	SandboxID   string              `json:"sandboxId"`
	SandboxName string              `json:"sandboxName"`
	EntryPoints []SandboxEntryPoint `json:"entryPoints"`
}

