	runtimev1alpha1 "github.com/volcano-sh/agentcube/pkg/apis/runtime/v1alpha1"
	"github.com/volcano-sh/agentcube/pkg/common/types"
)

func TestReconciler_Reconcile_NoAnnotation(t *testing.T) {
	sandbox := &runtimev1alpha1.AgentRuntime{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-sandbox",
			Namespace: "default",
		},
	}

	assert.Empty(t, sandbox.Annotations[types.LastActivityAnnotationKey])
}

func TestReconciler_Reconcile_InvalidTimestamp(t *testing.T) {
	invalidTime := "invalid-timestamp"

	_, err := time.Parse(time.RFC3339, invalidTime)
	assert.Error(t, err)
}

func TestReconciler_Reconcile_Expired(t *testing.T) {
	oldTime := time.Now().Add(-20 * time.Minute).Format(time.RFC3339)
	expirationTime, _ := time.Parse(time.RFC3339, oldTime)
	expirationTime = expirationTime.Add(SessionExpirationTimeout)

	assert.True(t, time.Now().After(expirationTime))
}

func TestReconciler_Reconcile_NotExpired(t *testing.T) {
	recentTime := time.Now().Add(-5 * time.Minute).Format(time.RFC3339)
	lastActivity, _ := time.Parse(time.RFC3339, recentTime)
	expirationTime := lastActivity.Add(SessionExpirationTimeout)

	assert.False(t, time.Now().After(expirationTime))
	assert.True(t, time.Until(expirationTime) > 0)
}

func TestSessionExpirationTimeout(t *testing.T) {
	assert.Equal(t, 15*time.Minute, SessionExpirationTimeout)
}

func TestReconciler_CodeInterpreter_NoAnnotation(t *testing.T) {
	sandbox := &runtimev1alpha1.CodeInterpreter{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-code-interpreter",
			Namespace: "default",
		},
	}

	assert.Empty(t, sandbox.Annotations[types.LastActivityAnnotationKey])
}

func TestReconciler_AgentRuntime_WithAnnotation(t *testing.T) {
	recentTime := time.Now().Add(-5 * time.Minute).Format(time.RFC3339)
	sandbox := &runtimev1alpha1.AgentRuntime{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-sandbox",
			Namespace: "default",
			Annotations: map[string]string{
				types.LastActivityAnnotationKey: recentTime,
			},
		},
	}

	assert.NotEmpty(t, sandbox.Annotations[types.LastActivityAnnotationKey])
	lastActivity, err := time.Parse(time.RFC3339, sandbox.Annotations[types.LastActivityAnnotationKey])
	assert.NoError(t, err)
	assert.True(t, time.Since(lastActivity) < 10*time.Minute)
}

